import pytest
import requests

BASE_URL = "<BASE_URL>"

@pytest.fixture
def admin_headers():
    return <get_auth_headers>(role="admin")

def test_admin_soft_delete_patient_returns_200(admin_headers):
    # Arrange: create a fresh patient
    payload = {"resourceType": "Patient", "name": [{"family": "TestDelete"}]}
    create_resp = requests.post(f"{BASE_URL}/Patient", json=payload, headers=admin_headers)
    assert create_resp.status_code in (200, 201)
    patient_id = create_resp.json()["id"]

    # Act: soft-delete
    delete_resp = requests.delete(f"{BASE_URL}/Patient/{patient_id}", headers=admin_headers)

    # Assert
    assert delete_resp.status_code in (200, 204), (
        f"Expected 200/204, got {delete_resp.status_code}"
    )

    # Verify resource still exists (soft-deleted)
    get_resp = requests.get(
        f"{BASE_URL}/Patient/{patient_id}",
        headers=admin_headers,
        params={"_summary": "true"}
    )
    # FHIR soft-delete: GET returns 410 with OperationOutcome referencing history
    assert get_resp.status_code in (200, 410), (
        f"Unexpected status after soft-delete: {get_resp.status_code}"
    )

import pytest
import requests

BASE_URL = "<BASE_URL>"

@pytest.fixture
def admin_headers():
    return <get_auth_headers>(role="admin")

@pytest.fixture
def practitioner_headers():
    return <get_auth_headers>(role="practitioner")

def test_non_admin_delete_patient_returns_403(admin_headers, practitioner_headers):
    # Arrange: create patient as admin
    payload = {"resourceType": "Patient", "name": [{"family": "Unauthorized"}]}
    create_resp = requests.post(f"{BASE_URL}/Patient", json=payload, headers=admin_headers)
    assert create_resp.status_code in (200, 201)
    patient_id = create_resp.json()["id"]

    # Act: attempt delete as non-admin
    delete_resp = requests.delete(
        f"{BASE_URL}/Patient/{patient_id}",
        headers=practitioner_headers
    )

    # Assert
    assert delete_resp.status_code == 403, (
        f"Expected 403 Forbidden, got {delete_resp.status_code}"
    )
    body = delete_resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    issues = body.get("issue", [])
    assert any(i.get("severity") == "error" for i in issues)

